<div class="box ph-card"><div class="box-header"><h3 class="box-title"><i class="fa fa-filter"></i> Filter Payroll History</h3></div><div class="box-body"><form class="form-horizontal" onsubmit="return false;"><div class="form-group"><label class="control-label col-lg-2"><?=hr_h('hr_period', 'Period');?></label><div class="col-lg-2"><div class="input-group date ph-date"><input id="filter_tgl_awal" class="form-control" value="<?=$defaultFrom;?>"><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div><div class="col-lg-2"><div class="input-group date ph-date"><input id="filter_tgl_akhir" class="form-control" value="<?=$defaultTo;?>"><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div><label class="control-label col-lg-1">Area</label><div class="col-lg-2"><select id="filter_payroll_area" class="form-control"><option value="">All</option><option>MONTHLY</option><option>DAILY</option><option>WEEKLY</option><option>CONTRACT</option><option>MANAGEMENT</option><option>ALL</option></select></div><label class="control-label col-lg-1">History</label><div class="col-lg-2"><select id="filter_history_status" class="form-control"><option value="">All</option><option>ACTIVE</option><option>ARCHIVED</option><option>LOCKED</option><option>VOID</option></select></div></div><div class="form-group"><label class="control-label col-lg-2"><?=hr_h('hr_payslip', 'Payslip');?></label><div class="col-lg-2"><select id="filter_payslip_status" class="form-control"><option value="">All</option><option>DRAFT</option><option>GENERATED</option><option>RELEASED</option><option>VOID</option><option>NOT_GENERATED</option></select></div><label class="control-label col-lg-1">Posting</label><div class="col-lg-2"><select id="filter_posting_status" class="form-control"><option value="">All</option><option>DRAFT</option><option>READY</option><option>POSTED</option><option>REVERSED</option><option>CANCELLED</option><option>NOT_CREATED</option></select></div><label class="control-label col-lg-1"><?=hr_h('hr_employee', 'Employee');?></label><div class="col-lg-2"><select id="filter_employee_id" class="form-control"></select></div><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="History, run, employee"></div></div><div class="form-group"><div class="col-lg-10 col-lg-offset-2"><button id="btn_filter_ph" class="btn btn-primary"><i class="fa fa-filter"></i> <?=hr_h('common_filter', 'Filter');?></button> <button id="btn_reset_ph" class="btn btn-default"><i class="fa fa-refresh"></i> <?=hr_h('common_reset', 'Reset');?></button></div></div></form></div></div>
