<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function phError(m){$('.isi_warning_delete').text(m||'Payroll History gagal diproses.');$('.error_data_delete').fadeIn();}
function phMoney(v){return (parseFloat(v||0)||0).toLocaleString('id-ID');}
function phFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),payroll_area:$('#filter_payroll_area').val(),history_status:$('#filter_history_status').val(),payslip_status:$('#filter_payslip_status').val(),posting_status:$('#filter_posting_status').val(),employee_id:$('#filter_employee_id').val(),keyword:$('#filter_keyword').val()};}
function phAjax(s,act,p,parent){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function phReset(){$('#form_payroll_history')[0].reset();$('#ph_id').val('');$('#payroll_employee_id').prop('disabled',false).val(null).trigger('change');$('#history_status').val('ACTIVE').trigger('change');$('#audit_source').val('AUTO_SNAPSHOT').trigger('change');$('#ph_modal_title').text('Create Payroll History Snapshot');}
$(function(){if($.fn.datepicker){$('.ph-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_payroll_area,#filter_history_status,#filter_payslip_status,#filter_posting_status,#history_status,#audit_source').select2({width:'100%',allowClear:true});phAjax('#filter_employee_id','employee_search','Pilih Employee');phAjax('#payroll_employee_id','payroll_employee_search','Pilih Payroll Result',$('#modal_payroll_history'));}
var dt=$('#dtb_payroll_history').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'180px',targets:1}],ajax:{url:'<?=base_admin();?>modul/payroll_history/payroll_history_data.php',type:'post',data:function(d){$.extend(d,phFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_locked').text(k.locked||0);$('#kpi_released').text(k.released||0);$('#kpi_posting').text(k.posting_ready||0);$('#kpi_net').text(phMoney(k.net));return j.data||[];},error:function(x){console.log(x.responseText);phError('Data Payroll History gagal dimuat.');}}});
$('#btn_open_ph').click(function(){phReset();$('#modal_payroll_history').modal({backdrop:'static',keyboard:false});});$('#btn_filter_ph').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_ph').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_payroll_area,#filter_history_status,#filter_payslip_status,#filter_posting_status,#filter_employee_id').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_ph').click(function(){window.location='<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act=export&'+$.param(phFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#form_payroll_history').submit(function(e){e.preventDefault();var edit=$('#ph_id').val()!=='';if(!edit&&!$('#payroll_employee_id').val()){phError('Payroll Result Employee wajib dipilih.');return;}var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act='+(edit?'update':'save'),$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Snapshot');if(r.status==='good'){$('#modal_payroll_history').modal('hide');dt.draw(false);Swal.fire('Saved','Payroll History berhasil disimpan.','success');}else phError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Snapshot');phError(x.responseText);});});
$(document).on('click','.btn-ph-detail',function(){$.post('<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act=detail',{id:$(this).data('id')},function(h){$('#ph_detail_body').html(h);$('#modal_ph_detail').modal('show');});});
$(document).on('click','.btn-ph-edit',function(){if($(this).is(':disabled'))return;phReset();$.post('<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act=get',{id:$(this).data('id')},function(r){if(r.status!=='good'){phError(r.error_message);return;}var d=r.data;$('#ph_id').val(d.id);$('#payroll_employee_id').prop('disabled',true).append(new Option(d.payroll_run_no+' - '+d.employee_no+' '+d.full_name,d.payroll_employee_id,true,true)).trigger('change');$('#history_status').val(d.history_status).trigger('change');$('#audit_source').val(d.audit_source).trigger('change');$('#remarks').val(d.remarks);$('#ph_modal_title').text('Edit Payroll History');$('#modal_payroll_history').modal({backdrop:'static',keyboard:false});},'json');});
function phSetStatus(id,status,label){$.post('<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(label,'Payroll History berhasil diubah.','success');}else phError(r.error_message);},'json');}
$(document).on('click','.btn-ph-lock',function(){phSetStatus($(this).data('id'),'LOCKED','Locked');});
$(document).on('click','.btn-ph-archive',function(){if($(this).is(':disabled'))return;phSetStatus($(this).data('id'),'ARCHIVED','Archived');});
$(document).on('click','.btn-ph-delete',function(){if($(this).is(':disabled'))return;var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/payroll_history/payroll_history_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else phError(r.error_message);},'json');});});
});
</script>
